import React, { useEffect, useRef, useState } from 'react';
import { Box, AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemIcon, ListItemText, Slider, Divider } from '@mui/material';
import { fabric } from 'fabric';
import styled from 'styled-components';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon,
  RadioButtonUnchecked as CircleIcon,
  CropSquare as RectangleIcon,
  ChangeHistory as TriangleIcon,
  Lens as PointIcon,
  ShowChart as LineIcon,
  Arc as ArcIcon,
  LensBlur as EllipseIcon,
  Functions as ParabolaIcon,
  CallSplit as HyperbolaIcon,
  Autorenew as CycloidIcon,
  CompareArrows as EpicycloidIcon,
  CompareArrows as HypocycloidIcon,
  RotateRight as SpiralIcon,
  Flip as MirrorIcon,
} from '@mui/icons-material';

const CanvasContainer = styled(Box)`
  flex-grow: 1;
  height: calc(100vh - 64px);
  background: white;
`;

const ToolbarButton = styled(IconButton)`
  margin: 0 8px;
`;

const ColorPicker = styled.input`
  width: 50px;
  height: 50px;
  padding: 0;
  border: none;
  border-radius: 4px;
  cursor: pointer;
`;

const App = () => {
  const canvasRef = useRef(null);
  const [canvas, setCanvas] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [currentColor, setCurrentColor] = useState('#000000');
  const [currentWidth, setCurrentWidth] = useState(2);
  const [currentTool, setCurrentTool] = useState(null);
  const [startPoint, setStartPoint] = useState(null);
  const [history, setHistory] = useState([]);
  const [redoStack, setRedoStack] = useState([]);

  useEffect(() => {
    const canvas = new fabric.Canvas(canvasRef.current, {
      width: window.innerWidth - 240,
      height: window.innerHeight - 64,
      backgroundColor: '#ffffff',
    });

    setCanvas(canvas);

    return () => {
      canvas.dispose();
    };
  }, []);

  const addToHistory = () => {
    if (canvas) {
      setHistory([...history, canvas.toJSON()]);
      setRedoStack([]);
    }
  };

  const handleUndo = () => {
    if (history.length > 0) {
      const previousState = history[history.length - 1];
      setRedoStack([...redoStack, canvas.toJSON()]);
      canvas.loadFromJSON(previousState, () => {
        canvas.renderAll();
      });
      setHistory(history.slice(0, -1));
    }
  };

  const handleRedo = () => {
    if (redoStack.length > 0) {
      const nextState = redoStack[redoStack.length - 1];
      setHistory([...history, canvas.toJSON()]);
      canvas.loadFromJSON(nextState, () => {
        canvas.renderAll();
      });
      setRedoStack(redoStack.slice(0, -1));
    }
  };

  const handleClear = () => {
    if (canvas) {
      canvas.clear();
      addToHistory();
    }
  };

  const handleMouseDown = (e) => {
    const pointer = canvas.getPointer(e.e);
    setStartPoint({ x: pointer.x, y: pointer.y });
  };

  const handleMouseMove = (e) => {
    if (!startPoint || !currentTool) return;

    const pointer = canvas.getPointer(e.e);
    canvas.remove(canvas.getObjects().pop());

    switch (currentTool) {
      case 'point':
        const point = new fabric.Circle({
          left: pointer.x - 3,
          top: pointer.y - 3,
          radius: 3,
          fill: currentColor,
          selectable: false,
        });
        canvas.add(point);
        break;

      case 'line':
        const line = new fabric.Line(
          [startPoint.x, startPoint.y, pointer.x, pointer.y],
          {
            stroke: currentColor,
            strokeWidth: currentWidth,
            selectable: false,
          }
        );
        canvas.add(line);
        break;

      case 'rectangle':
        const rect = new fabric.Rect({
          left: Math.min(startPoint.x, pointer.x),
          top: Math.min(startPoint.y, pointer.y),
          width: Math.abs(pointer.x - startPoint.x),
          height: Math.abs(pointer.y - startPoint.y),
          stroke: currentColor,
          strokeWidth: currentWidth,
          fill: 'transparent',
          selectable: false,
        });
        canvas.add(rect);
        break;

      case 'circle':
        const radius = Math.sqrt(
          Math.pow(pointer.x - startPoint.x, 2) + Math.pow(pointer.y - startPoint.y, 2)
        );
        const circle = new fabric.Circle({
          left: startPoint.x - radius,
          top: startPoint.y - radius,
          radius: radius,
          stroke: currentColor,
          strokeWidth: currentWidth,
          fill: 'transparent',
          selectable: false,
        });
        canvas.add(circle);
        break;

      case 'triangle':
        const triangle = new fabric.Triangle({
          left: Math.min(startPoint.x, pointer.x),
          top: Math.min(startPoint.y, pointer.y),
          width: Math.abs(pointer.x - startPoint.x),
          height: Math.abs(pointer.y - startPoint.y),
          stroke: currentColor,
          strokeWidth: currentWidth,
          fill: 'transparent',
          selectable: false,
        });
        canvas.add(triangle);
        break;

      case 'ellipse':
        const ellipse = new fabric.Ellipse({
          left: Math.min(startPoint.x, pointer.x),
          top: Math.min(startPoint.y, pointer.y),
          rx: Math.abs(pointer.x - startPoint.x) / 2,
          ry: Math.abs(pointer.y - startPoint.y) / 2,
          stroke: currentColor,
          strokeWidth: currentWidth,
          fill: 'transparent',
          selectable: false,
        });
        canvas.add(ellipse);
        break;

      // Add more shape cases here for parabola, hyperbola, cycloid, etc.
    }
  };

  const handleMouseUp = () => {
    if (startPoint && currentTool) {
      addToHistory();
    }
    setStartPoint(null);
  };

  useEffect(() => {
    if (canvas) {
      canvas.on('mouse:down', handleMouseDown);
      canvas.on('mouse:move', handleMouseMove);
      canvas.on('mouse:up', handleMouseUp);
    }
  }, [canvas, startPoint, currentTool, currentColor, currentWidth]);

  const tools = [
    { name: 'Point', icon: <PointIcon />, type: 'point' },
    { name: 'Line', icon: <LineIcon />, type: 'line' },
    { name: 'Rectangle', icon: <RectangleIcon />, type: 'rectangle' },
    { name: 'Circle', icon: <CircleIcon />, type: 'circle' },
    { name: 'Triangle', icon: <TriangleIcon />, type: 'triangle' },
    { name: 'Ellipse', icon: <EllipseIcon />, type: 'ellipse' },
    { name: 'Arc', icon: <ArcIcon />, type: 'arc' },
    { name: 'Parabola', icon: <ParabolaIcon />, type: 'parabola' },
    { name: 'Hyperbola', icon: <HyperbolaIcon />, type: 'hyperbola' },
    { name: 'Cycloid', icon: <CycloidIcon />, type: 'cycloid' },
    { name: 'Epicycloid', icon: <EpicycloidIcon />, type: 'epicycloid' },
    { name: 'Hypocycloid', icon: <HypocycloidIcon />, type: 'hypocycloid' },
    { name: 'Spiral', icon: <SpiralIcon />, type: 'spiral' },
    { name: 'Mirror', icon: <MirrorIcon />, type: 'mirror' },
  ];

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            Draze - Where Shapes Take Form
          </Typography>
          <ToolbarButton color="inherit" onClick={() => setDrawerOpen(true)}>
            <BrushIcon />
          </ToolbarButton>
          <ToolbarButton color="inherit" onClick={handleUndo}>
            <UndoIcon />
          </ToolbarButton>
          <ToolbarButton color="inherit" onClick={handleRedo}>
            <RedoIcon />
          </ToolbarButton>
          <ToolbarButton color="inherit" onClick={handleClear}>
            <DeleteIcon />
          </ToolbarButton>
        </Toolbar>
      </AppBar>

      <Drawer
        anchor="left"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
      >
        <List sx={{ width: 240 }}>
          {tools.map((tool) => (
            <ListItem
              button
              key={tool.type}
              onClick={() => setCurrentTool(tool.type)}
              selected={currentTool === tool.type}
            >
              <ListItemIcon>{tool.icon}</ListItemIcon>
              <ListItemText primary={tool.name} />
            </ListItem>
          ))}
          <Divider />
          <ListItem>
            <ListItemIcon>
              <ColorLensIcon />
            </ListItemIcon>
            <ColorPicker
              type="color"
              value={currentColor}
              onChange={(e) => setCurrentColor(e.target.value)}
            />
          </ListItem>
          <ListItem>
            <ListItemText primary="Line Width" />
            <Slider
              value={currentWidth}
              onChange={(e, newValue) => setCurrentWidth(newValue)}
              min={1}
              max={10}
              sx={{ width: 100 }}
            />
          </ListItem>
        </List>
      </Drawer>

      <CanvasContainer>
        <canvas ref={canvasRef} />
      </CanvasContainer>
    </Box>
  );
};

export default App;
